class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def find_nth_from_end(head: ListNode, n: int) -> ListNode:
    if not head:
        return None

    slow = head
    fast = head

    # Hızlı işaretçiyi n adım ileri taşı
    for _ in range(n):
        if not fast:
            # Eğer fast, n adım tamamlanmadan None olursa,
            # bu n'in bağlı listenin uzunluğundan büyük olduğu anlamına gelir.
            return None
        fast = fast.next

    # Şimdi, fast sona ulaşana kadar her iki işaretçiyi de hareket ettir
    # fast None olduğunda, slow sondan n'inci düğümde olacaktır.
    while fast:
        slow = slow.next
        fast = fast.next

    return slow
